CREATE TRIGGER IF NOT EXISTS trg_match_stage_update
AFTER UPDATE OF stage ON match
FOR EACH ROW
BEGIN
    UPDATE dependency SET stage1 = NEW.stage WHERE match1 = NEW.id;
    UPDATE dependency SET stage2 = NEW.stage WHERE match2 = NEW.id;
END;

UPDATE match SET stage = stage + 1 WHERE id = 'match1'

